-- settings.device
hl.device({
  ["name"] = "epic-mouse-v1",
  ["sensitivity"] = -0.5
})

-- settings.env
hl.env("XCURSOR_SIZE", "24")
hl.env("HYPRCURSOR_SIZE", "24")

-- settings.gesture
hl.gesture({
  ["action"] = "workspace",
  ["direction"] = "horizontal",
  ["fingers"] = 3
})

-- settings.monitor
hl.monitor({
  ["mode"] = "1920x1080@60",
  ["output"] = "desc:AU Optronics 0x4F8A",
  ["position"] = "0x0",
  ["scale"] = 1
})
hl.monitor({
  ["mode"] = "2560x1440@75",
  ["output"] = "desc:HP Inc. HP E27q G5 CNC42530PR",
  ["position"] = "-2560x0",
  ["scale"] = 1
})
hl.monitor({
  ["mode"] = "2560x1440@120",
  ["output"] = "desc:Dell Inc. DELL U2724DE 7W4FCP3",
