-- settings.on
hl.on("hyprland.start", (function()
  hl.exec_cmd("systemctl --user start hyprpolkitagent")
  hl.exec_cmd("nm-applet")
  hl.exec_cmd("waybar")
end))

-- settings.window_rule
hl.window_rule({
  ["match"] = {
    ["class"] = ".*"
  },
  ["name"] = "Ignore maximise requests from apps",
  ["suppress_event"] = "maximize"
})
hl.window_rule({
  ["center"] = true,
  ["float"] = true,
  ["match"] = {
    ["initial_class"] = "^thunderbird$",
    ["initial_title"] = "^Write"
  },
  ["name"] = "Thunderbird composing"
})
hl.window_rule({
  ["center"] = true,
  ["float"] = true,
  ["match"] = {
    ["initial_class"] = "^org.gnome.NautilusPreviewer$"
  },
  ["name"] = "Nautilus Previewer"
})
hl.window_rule({
  ["group"] = "set",
  ["match"] = {
    ["class"] = "^org.gnome.Papers$"
  },
  ["name"] = "Group Papers windows"
})

-- startup
hl.on("hyprland.start", function()
  hl.exec_cmd("/nix/store/2avx2c74smgw4ghki0qlnc0scgpfycbl-dbus-1.16.2/bin/dbus-update-activation-environment --systemd DISPLAY HYPRLAND_INSTANCE_SIGNATURE WAYLAND_DISPLAY XDG_CURRENT_DESKTOP XDG_SESSION_TYPE && systemctl --user stop hyprland-session.target && systemctl --user start hyprland-session.target")
end)

-- extraConfig
for i = 1, 10 do
    local key = i % 10 -- 10 maps to key 0
    hl.bind(mainMod .. " + " .. key,             hl.dsp.focus({ workspace = i}))
    hl.bind(mainMod .. " + SHIFT + " .. key,     hl.dsp.window.move({ workspace = i }))
end
